\begin{figure}[h]\centering

\end{figure}

Formation of a shock

\textbf{b. Shocks, entropy condition.}

We try now to solve a similar problem by the same techniques.

\textbf{a. Entropy condition revisited.}

We have already seen in \S 3.4.1 that integral solutions of (1) are not generally unique. Since we believe the Lax--Oleinik formula does in fact provide the ``correct'' solution of this initial-value problem, we must see if it satisfies some appropriate form of the entropy condition discussed in \S 3.4.1. This is not straightforward, however, since it is not usually the case that the function $u$ defined by the Lax--Oleinik formula is smooth, or even piecewise smooth.

We identify now a kind of ``one-sided'' derivative estimate for the function $u$ defined by the Lax--Oleinik formula (27). This estimate---which is an analogue for conservation laws of the semiconcavity estimate from \cref{lem:hopf-lax-semiconcavity-from-data,lem:hopf-lax-semiconcavity-uniform-convexity} in \S 3.3.3 for Hamilton--Jacobi equations---will turn out to be a uniqueness criterion.

\begin{exercise}
Prove
$$u(x,t,a,b) = a \cdot x - tH(a) + b \quad (a \in \R^n, b \in \R)$$
is a complete integral of the Hamilton-Jacobi equation
$$u_t + H(Du) = 0.$$
\end{exercise}


\begin{exercise}
(a) Write down the characteristic equations for the PDE
$$(*)  \quad u_t + b \cdot Du = f \quad \text{in } \R^n \times (0,\infty),$$
where $b \in \R^n$, $f = f(x,t)$.

(b) Use the characteristic ODE to solve $(*)$ subject to the initial condition
$$u = g \text{ on } \R^n \times \{t = 0\}.$$
Make sure your answer agrees with formula (5) in \S2.1.2.
\end{exercise}


\begin{exercise}
Solve using characteristics:

(a) $x_1 u_{x_1} + x_2 u_{x_2} = 2u$, $u(x_1, 1) = g(x_1)$.

(b) $uu_{x_1} + u_{x_2} = 1$, $u(x_1, x_1) = \frac{1}{2}x_1$.

(c) $x_1 u_{x_1} + 2x_2 u_{x_2} = 3u$, $u(x_1, x_2, 0) = g(x_1, x_2)$.
\end{exercise}


\begin{exercise}
Verify that formula (61) in \S3.2.5 provides an implicit solution of the scalar conservation law.
\end{exercise}


\begin{exercise}
Write $L = H^*$, if $H : \R^n \to \R$ is convex.

(a) Let $H(p) = \frac{1}{r}|p|^r$, for $1 < r < \infty$. Show
$$L(q) = \frac{1}{s}|q|^s, \quad \text{where } \frac{1}{r} + \frac{1}{s} = 1.$$

(b) Let $H(p) = \frac{1}{2}\sum_{i,j=1}^n a_{ij}p_i p_j + \sum_{i=1}^n b_i p_i$, where $A = ((a_{ij}))$ is a symmetric, positive definite matrix, $b \in \R^n$. Compute $L(q)$.
\end{exercise}


\begin{exercise}
Let $H : \R^n \to \R$ be convex. We say $q$ belongs to the \textit{subdifferential} of $H$ at $p$, written
$$q \in \partial H(p),$$
if
$$H(r) \geq H(p) + q \cdot (r - p) \quad \text{for all } r \in \R^n.$$
Prove $q \in \partial H(p)$ if and only if $p \in \partial L(q)$ if and only if $p \cdot q = H(p) + L(q)$, where $L = H^*$.
\end{exercise}


\begin{exercise}
Prove that the Hopf-Lax formula reads
$$u(x,t) = \min_{y \in \R^n} \left\{ tL\left(\frac{x-y}{t}\right) + g(y)\right\}$$
$$= \min_{y \in B(x, Rt)} \left\{ tL\left(\frac{x-y}{t}\right) + g(y)\right\}$$
for $R = \sup_{\R^n} |DH(Dg)|$, $H = L^*$. (This proves \textit{finite propagation speed} for a Hamilton-Jacobi PDE with convex Hamiltonian and Lipschitz continuous initial function $g$. Hint: Use the previous problem.)
\end{exercise}


\begin{exercise}
Let $E$ be a closed subset of $\R^n$. Show that if the Hopf-Lax formula could be applied to the initial-value problem
$$\begin{cases}
u_t + |Du|^2 = 0 & \text{in } \R^n \times (0, \infty) \\
u = \begin{cases} 0 & x \in E \\ +\infty & x \notin E \end{cases} & \text{on } \R^n \times \{t = 0\},
\end{cases}$$
it would give the solution

$$u(x,t) = \frac{1}{4t}\dist(x, E)^2.$$
\end{exercise}


\begin{exercise}
Fill in all details for the proof of \cref{lem:hopf-lax-semiconcavity-uniform-convexity} in \S3.3.3.
\end{exercise}


\begin{exercise}
Assume $u^1, u^2$ are two weak solutions of the initial-value problems
$$
\begin{cases}
u_t^i + H(Du^i) = 0 & \text{in } \R^n \times (0, \infty) \\
u^i = g^i & \text{on } \R^n \times \{t = 0\} \quad (i = 1,2),
\end{cases}
$$
for $H$ as in \S3.3. Prove the $L^\infty$-contraction inequality
$$\sup_{\R} |u^1(\cdot, t) - u^2(\cdot, t)| \leq \sup_{\R} |g^1 - g^2| \quad (t > 0).$$
\end{exercise}


\begin{exercise}
Show that
$$u(x,t) = \begin{cases} -\frac{2}{3}\left(t + \sqrt{3x + t^2}\right) & \text{if } 4x + t^2 > 0 \\ 0 & \text{if } 4x + t^2 < 0 \end{cases}$$
is an (unbounded) entropy solution of $u_t + \left(\frac{u^2}{2}\right)_x = 0$.
\end{exercise}


\begin{exercise}
Assume $u(x+z) - u(x) \leq Ez$ for all $z > 0$. Let $u^\epsilon = \eta_\epsilon * u$, and show
$$u_x^\epsilon \leq E.$$
\end{exercise}


\begin{exercise}
Assume $F(0) = 0$, $u$ is a continuous integral solution of the conservation law
$$
\begin{cases}
u_t + F(u)_x = 0 & \text{in } \R \times (0, \infty) \\
u = g & \text{on } \R \times \{t = 0\},
\end{cases}
$$
and $u$ has compact support in $\R \times [0, \infty)$. Prove
$$\int_{-\infty}^{\infty} u(x,t) dx = \int_{-\infty}^{\infty} g\,dx$$
for all $t > 0$.
\end{exercise}


\begin{exercise}
Compute explicitly the unique entropy solution of
$$
\begin{cases}
u_t + \left(\frac{u^2}{2}\right)_x = 0 & \text{in } \R \times (0, \infty) \\
u = g & \text{on } \R \times \{t = 0\},
\end{cases}
$$
for
$$g(x) = \begin{cases} 1 & \text{if } x < -1 \\ 0 & \text{if } -1 < x < 0 \\ 2 & \text{if } 0 < x < 1 \\ 0 & \text{if } x > 1. \end{cases}$$
Draw a picture documenting your answer, being sure to illustrate what happens for all times $t > 0$.
\end{exercise}

blocks.body:
If $u\in L^1(\R^n)$, we define its \textit{Fourier transform}
$$(1) \quad \hat u(y) := \frac{1}{(2\pi)^{n/2}}\int_{\R^n} e^{-ix\cdot y}u(x)\,dx \quad (y\in\R^n)$$
and its \textit{inverse Fourier transform}
$$(2) \quad \check u(y) := \frac{1}{(2\pi)^{n/2}}\int_{\R^n} e^{ix\cdot y}u(x)\,dx \quad (y\in\R^n).$$
Since $|e^{\pm ix\cdot y}|=1$ and $u\in L^1(\R^n)$, these integrals converge for each $y\in\R^n$.

blocks.tex:
\begin{exercise}
Use separation of variables to find a nontrivial solution $u$ of the PDE
$$u^2_{x_1}u_{x_1x_1} + 2u_{x_1}u_{x_2}u_{x_1x_2} + u^2_{x_2}u_{x_2x_2} = 0 \quad \text{in } \R^2.$$
\end{exercise}


\begin{exercise}
Consider Laplace's equation $\Delta u = 0$ in $\R^2$, taken with the Cauchy data
$$u = 0, \quad \frac{\partial u}{\partial x_2} = \frac{1}{n}\sin(nx_1) \quad \text{on } \{x_2 = 0\}.$$
Employ separation of variables to derive the solution
$$u = \frac{1}{n^2} \sin(nx_1) \sinh(nx_2).$$
What happens to $u$ as $n \to \infty$? Is the Cauchy problem for Laplace's equation well-posed? (This example is due to Hadamard.)
\end{exercise}


\begin{exercise}
Consider the viscous conservation law
$$(*)  \quad u_t + F(u)_x - au_{xx} = 0 \quad \text{in } \R \times (0, \infty),$$
where $a > 0$ and $F$ is uniformly convex.

(i) Show $u$ solves $(*)$ if $u(x, t) = v(x - \sigma t)$ and $v$ is defined implicitly by the formula
$$s = \int_c^{v(s)} \frac{a}{F(z) - \sigma z + b} \, dz \quad (s \in \R),$$
where $b$ and $c$ are constants.

(ii) Demonstrate that we can find a traveling wave satisfying
$$\lim_{s \to -\infty} v(s) = u_l, \quad \lim_{s \to \infty} v(s) = u_r$$
for $u_l > u_r$, if and only if
$$\sigma = \frac{F(u_l) - F(u_r)}{u_l - u_r}.$$

(iii) Let $u^\varepsilon$ denote the above traveling wave solution of $(*)$ for $a = \varepsilon$, with $u^\varepsilon(0, 0) = \frac{u_l + u_r}{2}$. Compute $\lim_{\varepsilon \to 0} u^\varepsilon$ and explain your answer.
\end{exercise}


\begin{exercise}
Prove that if $u$ is the solution of problem (23) for Schr\"odinger's equation in \S4.3 given by formula (20), then
$$\|u(\cdot, t)\|_{L^\infty(\R^n)} \leq \frac{1}{(4\pi |t|)^{n/2}} \|g\|_{L^1(\R^n)}$$
for each $t \neq 0$.
\end{exercise}


\begin{exercise}
Utilize Lemma 2 in \S4.5.3 to discuss the sense in which $u$ defined by formula (20) in \S4.3.1 converges to the initial data $g$ as $t \to 0^+$.
\end{exercise}


\begin{exercise}
Show that we can construct an explicit solution of the initial-value problem (18), (19) from Example 1 in \S4.5.1, having the form
$$v(z, t) = \frac{1}{\sigma(t)} \frac{1}{(\pi\gamma(t))^{1/2}} e^{-z^2/\gamma(t)} \quad (z \in \R, t > 0),$$
the function $\gamma(t)$ to be found. Substitute into the PDE and determine an ODE $\gamma$ should satisfy. What is the initial condition for this ODE?
\end{exercise}


\begin{exercise}
Justify in the proof of Lemma 2 in \S4.5.3 the transformation of the integral of $e^{-z^2}$ over the line $\Gamma$ to the integral over the real axis.
\end{exercise}


\begin{exercise}
Let $n=1$ and suppose that $u^\varepsilon$ solves the problem
$$\begin{cases} -(a(\frac{x}{\varepsilon})u^\varepsilon_x)_x = f & \text{in } (0,1) \\ u^\varepsilon(0)=u^\varepsilon(1)=0, \end{cases}$$
where $a$ is a smooth, positive function, which is 1-periodic. Assume also that $f\in L^2(0,1)$.

(i) Show that $u^\varepsilon\rightharpoonup u$ weakly in $H_0^1(0,1)$, where $u$ solves
$$\begin{cases} -\bar a u_{xx}=f & \text{in } (0,1) \\ u(0)=u(1)=0, \end{cases}$$
for $\bar a := (\int_0^1 a(y)^{-1}\,dy)^{-1}$.

(ii) Check that this answer agrees with the conclusions (73), (74) in \S4.5.4.

(This problem requires knowledge of energy estimates, Sobolev spaces, etc. from Chapters 5, 6.)
\end{exercise}


\begin{exercise}
Show that the line $\{t=0\}$ is characteristic for the heat equation $u_t=u_{xx}$. Show there does not exist an analytic solution $u$ of the heat equation in $\R \times \R$, with $u=\frac{1}{1+x^2}$ on $\{t=0\}$. (Hint: Assume there is an analytic solution, compute its coefficients, and show that the resulting power series diverges except at $(0,0)$. This example is due to Kovalevskaya.)
\end{exercise}

blocks.body:
Assume $u \in W^{k,p}(U)$ for some $1 \le p < \infty$, and set
$$u^\varepsilon = \eta_\varepsilon * u \text{ in } U_\varepsilon.$$
Then
\begin{enumerate}
\item[(i)] $u^\varepsilon \in C^\infty(U_\varepsilon)$ for each $\varepsilon > 0$,
\end{enumerate}
and
\begin{enumerate}
\item[(ii)] $u^\varepsilon \to u$ in $W^{k,p}_{\text{loc}}(U)$, as $\varepsilon \to 0$.
\end{enumerate}

Assume $U$ is bounded and $\partial U$ is $C^1$. Select a bounded open set $V$ such that $U \CC V$. Then there exists a bounded linear operator
$$(1) \quad E: W^{1,p}(U) \to W^{1,p}(\R^n)$$
such that for each $u \in W^{1,p}(U)$:
\begin{itemize}
\item[(i)] $Eu = u$ a.e. in $U$,
\item[(ii)] $Eu$ has support within $V$,
\end{itemize}
and
\begin{itemize}
\item[(iii)] $\|Eu\|_{W^{1,p}(\R^n)} \le C\|u\|_{W^{1,p}(U)},$
\end{itemize}
the constant $C$ depending only on $p$, $U$, and $V$.

Assume $U$ is bounded and $\partial U$ is $C^1$. Then there exists a bounded linear operator
$$T : W^{1,p}(U) \to L^p(\partial U)$$
such that
\begin{itemize}
\item[(i)] $Tu = u|_{\partial U}$ if $u \in W^{1,p}(U) \cap C(\overline{U})$
\end{itemize}
and
\begin{itemize}
\item[(ii)] $$\|Tu\|_{L^p(\partial U)} \le C\|u\|_{W^{1,p}(U)},$$
\end{itemize}
for each $u \in W^{1,p}(U)$, with the constant $C$ depending only on $p$ and $U$.

