When we later apply Sobolev space theory to PDE, we will be forced to study difference quotient approximations to weak derivatives. Following is the relevant theory, which the reader may wish to postpone studying until the need arises, in §6.3.

\textbf{a. Difference quotients and $W^{1,p}$.}

Assume $u : U \to \R$ is a locally summable function, and $V \CC U$.

blocks.body:
The space
$$L^p(0, T; X)$$
consists of all measurable functions $\mathbf{u} : [0, T] \to X$ with
\begin{itemize}
\item[(i)] $\|\mathbf{u}\|_{L^p(0,T;X)} := \left(\int_0^T \|\mathbf{u}(t)\|^p\,dt\right)^{1/p} < \infty$
\end{itemize}
for $1 \le p < \infty$, and
\begin{itemize}
\item[(ii)] $\|\mathbf{u}\|_{L^\infty(0,T;X)} := \text{ess sup}_{0 \le t \le T} \|\mathbf{u}(t)\| < \infty$.
\end{itemize}

blocks.tex:
In these exercises $U$ always denotes an open subset of $\R^n$.


\begin{exercise}
Suppose $k \in \{0,1,\ldots\}$, $0 < \gamma \le 1$. Prove $C^{k,\gamma}(\bar U)$ is a Banach space.
\end{exercise}


\begin{exercise}
Let $U$, $V$ be open sets, with $V \CC U$. Show there exists a smooth function $\zeta$ such that $\zeta \equiv 1$ on $V$, $\zeta = 0$ near $\partial U$. (Hint: Take $V \CC W \CC U$ and mollify $\chi_W$.)
\end{exercise}


\begin{exercise}
Assume $0 < \beta < \gamma \le 1$. Prove the interpolation inequality
$$\|u\|_{C^{0,\gamma}(U)} \le \|u\|^{\frac{1-\gamma}{1-\beta}}_{C^{0,\beta}(U)} \|u\|^{\frac{\gamma-\beta}{1-\beta}}_{C^{0,1}(U)}.$$
\end{exercise}


\begin{exercise}
Assume $U$ is bounded and $U \CC \bigcup_{i=1}^N V_i$. Show there exist $C^\infty$ functions $\zeta_i$ ($i = 1, \ldots, N$) such that
$$\begin{cases}
0 \le \zeta_i \le 1, \text{ spt}\,\zeta_i \subset V_i \quad (i = 1, \ldots, N) \\
\sum_{i=1}^N \zeta_i = 1 \text{ on } U.
\end{cases}$$
The functions $\{\zeta_i\}_{i=1}^N$ form a \textit{partition of unity}.
\end{exercise}


\begin{exercise}
Prove that if $n = 1$ and $u \in W^{1,p}(0,1)$ for some $1 \le p < \infty$, then $u$ is equal a.e. to an absolutely continuous function, and $u'$ (which exists a.e.) belongs to $L^p(0,1)$.
\end{exercise}


\begin{exercise}
Prove directly that if $u \in W^{1,p}(0,1)$ for some $1 < p < \infty$, then
$$|u(x) - u(y)| \le |x - y|^{1-\frac{1}{p}} \left(\int_0^1 |u'|^p\,dt\right)^{1/p} \quad \text{for a.e. } x, y \in [0,1].$$
\end{exercise}


\begin{exercise}
Denote by $U$ the open square $\{x \in \R^2 \mid |x_1| < 1, |x_2| < 1\}$. Define
$$u(x) = \begin{cases}
1 - x_1 & \text{if } x_1 > 0, |x_2| < x_1 \\
1 + x_1 & \text{if } x_1 < 0, |x_2| < -x_1 \\
1 - x_2 & \text{if } x_2 > 0, |x_1| < x_2 \\
1 + x_2 & \text{if } x_2 < 0, |x_1| < -x_2.
\end{cases}$$
For which $1 \le p \le \infty$ does $u$ belong to $W^{1,p}(U)$?
\end{exercise}


\begin{exercise}
Integrate by parts to prove the interpolation inequality:
$$\int_U |Du|^2\,dx \le C \left(\int_U u^2\,dx\right)^{1/2} \left(\int_U |D^2u|^2\,dx\right)^{1/2}$$
for all $u \in C_c^\infty(U)$. By approximation, prove this inequality if $u \in H^2(U) \cap H^1_0(U)$.
\end{exercise}


\begin{exercise}
Integrate by parts to prove:
$$\int_U |Du|^p\,dx \le C \left(\int_U |u|^p\,dx\right)^{1/2} \left(\int_U |D^2u|^p\,dx\right)^{1/2}$$
for $2 \le p < \infty$ and all $u \in W^{2,p}(U) \cap W^{1,p}_0(U)$. (Hint: $\int_U |Du|^p\,dx = \sum_{i=1}^n \int_U u_{x_i} u_{x_i} |Du|^{p-2}\,dx.$)
\end{exercise}


\begin{exercise}
Suppose $U$ is connected and $u \in W^{1,p}(U)$ satisfies
$$Du = 0 \text{ a.e. in } U.$$
Prove $u$ is constant a.e. in $U$.
\end{exercise}


\begin{exercise}
Show by example that if we have $\|D^h u\|_{L^1(V)} < C$ for all $0 < |h| < \frac{1}{2}\dist(V, \partial U)$, it does not necessarily follow that $u \in W^{1,1}(V)$.
\end{exercise}


\begin{exercise}
Give an example of an open set $U \subset \R^n$ and a function $u \in W^{1,\infty}(U)$, such that $u$ is \textit{not} Lipschitz continuous on $U$. (Hint: Take $U$ to be the open unit disk in $\R^2$, with a slit removed.)
\end{exercise}


\begin{exercise}
Verify that if $n > 1$, the unbounded function $u = \log \log\left(1 + \frac{1}{|x|}\right)$ belongs to $W^{1,n}(U)$, for $U = B^0(0,1)$.
\end{exercise}


\begin{exercise}
Let $U$ be bounded, with a $C^1$ boundary. Show that a ``typical'' function $u \in L^p(U)$ ($1 \le p < \infty$) does not have a trace on $\partial U$. More precisely, prove there does not exist a bounded linear operator
$$T : L^p(U) \to L^p(\partial U)$$
such that $Tu = u|_{\partial U}$ whenever $u \in C(\bar{U}) \cap L^p(U)$.
\end{exercise}


\begin{exercise}
Fix $\alpha > 0$ and let $U = B^0(0,1)$. Show there exists a constant $C$, depending only on $n$ and $\alpha$, such that
$$\int_U u^2\,dx \le C \int_U |Du|^2\,dx,$$
provided
$$|\{x \in U \mid u(x) = 0\}| \ge \alpha, \quad u \in H^1(U).$$
\end{exercise}


\begin{exercise}
Assume $F : \R \to \R$ is $C^1$, with $F'$ bounded. Suppose $U$ is bounded and $u \in W^{1,p}(U)$ for some $1 < p < \infty$. Show
$$v := F(u) \in W^{1,p}(U) \text{ and } v_{x_i} = F'(u) u_{x_i} \quad (i = 1, \ldots, n).$$
\end{exercise}


\begin{exercise}
Assume $1 < p < \infty$, and $U$ is bounded.

(i) Prove that if $u \in W^{1,p}(U)$, then $|u| \in W^{1,p}(U)$.

(ii) Prove $u \in W^{1,p}(U)$ implies $u^+, u^- \in W^{1,p}(U)$, and
$$Du^+ = \begin{cases} Du & \text{a.e. on } \{u > 0\} \\ 0 & \text{a.e. on } \{u \le 0\} \end{cases}$$
$$Du^- = \begin{cases} 0 & \text{a.e. on } \{u \ge 0\} \\ -Du & \text{a.e. on } \{u < 0\}. \end{cases}$$
(Hint: $u^+ = \lim_{\varepsilon \to 0} F_\varepsilon(u)$, for
$$F_\varepsilon(z) := \begin{cases} (z^2 + \varepsilon^2)^{1/2} - \varepsilon & \text{if } z \ge 0 \\ 0 & \text{if } z < 0. \end{cases}$$
)

(iii) Prove that if $u \in W^{1,p}(U)$, then
$$Du = 0 \text{ a.e. on the set } \{u = 0\}.$$
\end{exercise}


\begin{exercise}
Use the Fourier transform to prove that if $u \in H^s(\R^n)$ for $s > n/2$, then $u \in L^\infty(\R^n)$, with the bound
$$\|u\|_{L^\infty(\R^n)} \le C\|u\|_{H^s(\R^n)},$$
the constant $C$ depending only on $s$ and $n$.
\end{exercise}

In the following exercises we assume the coefficients of the various PDE are smooth and satisfy the uniform ellipticity condition. Also $U \subset \R^n$ is always an open, bounded set, with smooth boundary.


\begin{exercise}
Let
$$Lu = -\sum_{i,j=1}^n (a^{ij}u_{x_i})_{x_j} + cu.$$
Prove that there exists a constant $\mu > 0$ such that the corresponding bilinear form $B[\cdot,\cdot]$ satisfies the hypotheses of the Lax--Milgram Theorem, provided
$$c(x) \geq -\mu \quad (x \in U).$$
\end{exercise}


\begin{exercise}
A function $u \in H_0^2(U)$ is a weak solution of this boundary-value problem for the \textit{biharmonic equation}
$$(*) \qquad \begin{cases} \Delta^2u = f & \text{in } U \\ u = \frac{\partial u}{\partial\nu} = 0 & \text{on } \partial U \end{cases}$$
provided
$$\int_U \Delta u \Delta v\,dx = \int_U fv\,dx$$
for all $v \in H_0^2(U)$. Given $f \in L^2(U)$, prove that there exists a unique weak solution of $(*)$.
\end{exercise}


\begin{exercise}
Assume $U$ is connected. A function $u \in H^1(U)$ is a weak solution of \textit{Neumann's problem}
$$(*) \qquad \begin{cases} -\Delta u = f & \text{in } U \\ \frac{\partial u}{\partial\nu} = 0 & \text{on } \partial U \end{cases}$$
if
$$\int_U Du \cdot Dv\,dx = \int_U fv\,dx$$
for all $v \in H^1(U)$. Suppose $f \in L^2(U)$. Prove $(*)$ has a weak solution if and only if
$$\int_U f\,dx = 0.$$
\end{exercise}


\begin{exercise}
Let $u \in H^1(\R^n)$ have compact support and be a weak solution of the semilinear PDE
$$-\Delta u + c(u) = f \quad \text{in } \R^n,$$
where $f \in L^2(\R^n)$ and $c : \R \to \R$ is smooth, with $c(0) = 0$ and $c' \geq 0$. Prove $u \in H^2(\R^n)$.

(Hint: Mimic the proof of Theorem 1 in \S6.3.1, but without the cutoff function $\zeta$.)
\end{exercise}


\begin{exercise}
Let $u$ be a smooth solution of $Lu = -\sum_{i,j=1}^n a^{ij}u_{x_ix_j} = 0$ in $U$. Set $v := |Du|^2 + \lambda u^2$. Show that
$$Lv \leq 0 \quad \text{in } U, \text{ if } \lambda \text{ is large enough.}$$
Deduce
$$\|Du\|_{L^\infty(U)} \leq C(\|Du\|_{L^\infty(\partial U)} + \|u\|_{L^\infty(\partial U)}).$$
\end{exercise}


\begin{exercise}
Assume $u$ is a smooth solution of $Lu = -\sum_{i,j=1}^n a^{ij}u_{x_ix_j} = f$ in $U$, $u = 0$ on $\partial U$, where $f$ is bounded. Fix $x^0 \in \partial U$. A barrier at $x^0$ is a $C^2$ function $w$ such that
$$Lw \geq 1 \text{ in } U, \quad w(x^0) = 0, \quad w \geq 0 \text{ on } \partial U.$$
Show that if $w$ is a barrier at $x^0$, there exists a constant $C$ such that
$$|Du(x^0)| \leq C\left|\frac{\partial w}{\partial\nu}(x^0)\right|.$$
\end{exercise}


\begin{exercise}
Assume $U$ is connected. Use (a) energy methods and (b) the maximum principle to show that the only smooth solutions of the Neumann boundary-value problem
$$\begin{cases} -\Delta u = 0 & \text{in } U \\ \frac{\partial u}{\partial\nu} = 0 & \text{on } \partial U \end{cases}$$
are $u \equiv \text{constant}$.
\end{exercise}


\begin{exercise}
Assume $u \in H^1(U)$ is a bounded weak solution of
$$-\sum_{i,j=1}^n (a^{ij}u_{x_i})_{x_j} = 0 \quad \text{in } U.$$
Let $\phi : \R \to \R$ be convex and smooth, and set $w = \phi(u)$. Show $w$ is a weak subsolution; that is,
$$B[w,v] \leq 0$$
for all $v \in H_0^1(U)$, $v \geq 0$.
\end{exercise}


\begin{exercise}
(\textit{Courant minmax principle}). Let $L = -\sum_{i,j=1}^n (a^{ij}u_{x_i})_{x_j}$, where $(a^{ij})$ is symmetric. Assume the operator $L$, with zero boundary conditions, has eigenvalues $0 < \lambda_1 < \lambda_2 \leq \cdots$. Show
$$\lambda_k = \max_{S \in \Sigma_{k-1}} \min_{\substack{u \in S^\perp \\ \|u\|_{L^2}=1}} B[u,u] \quad (k=1,2,\ldots).$$
Here $\Sigma_{k-1}$ denotes the collection of $(k-1)$-dimensional subspaces of $H_0^1(U)$.
\end{exercise}


\begin{exercise}
Let $\lambda_1$ be the principal eigenvalue of the uniformly elliptic, nonsymmetric operator
$$Lu = -\sum_{i,j=1}^n a^{ij}u_{x_ix_j} + \sum_{i=1}^n b^iu_{x_i} + cu,$$
taken with zero boundary conditions. Prove the ``max-min'' representation formula:
$$\lambda_1 = \sup_u \inf_x \frac{Lu(x)}{u(x)},$$
the ``sup'' taken over functions $u \in C^\infty(\bar U)$ with $u > 0$ in $U$, $u = 0$ on $\partial U$, and the ``inf'' taken over points $x \in U$. (Hint: Consider the eigenfunction $w_1^*$ corresponding to $\lambda_1$ for the adjoint operator $L^*$.)
\end{exercise}

We will instead calculate using the Galerkin approximations. To streamline the presentation, we hereafter assume that $\{w_k\}_{k=1}^\infty$ is the complete collection of eigenfunctions for $-\Delta$ on $H_0^1(U)$, and that $U$ is bounded, open, with $\partial U$ smooth. We furthermore suppose that
\[
\begin{cases} \text{the coefficients } a^{ij}, b^i, c \text{ } (i,j = 1, \ldots, n) \text{ are smooth on} \\ \bar{U} \text{ and do not depend on } t. \end{cases}
\tag{45}
\]

