An expression of the form
\begin{equation}
F(D^k u(x), D^{k-1} u(x), \ldots, Du(x), u(x), x) = 0 \qquad (x \in U)
\tag{1}
\end{equation}
is called a $k$th-order partial differential equation, where
$$F : \R^{n^k} \times \R^{n^{k-1}} \times \cdots \times \R^n \times \R \times U \to \R$$
is given, and
$$u : U \to \R$$
is the unknown.

lean.code:
def IsPDESolutionOn (k : ℕ) (U : Set E) (Φ : PDEJet k E F → E → F) (u : E → F) :
    Prop :=
  ∀ x ∈ U, Φ (pdeJet k u x) x = 0

def IsHomogeneousLinearPDE (k : ℕ) (Φ : PDEJet k E ℝ → E → ℝ) : Prop :=
  ∃ a : (j : Fin (k + 1)) → E → (PDEJetSlot (j : ℕ) E ℝ →L[ℝ] ℝ),
    ∀ (ξ : PDEJet k E ℝ) (x : E), Φ ξ x = ∑ j, a j x (ξ j)

def IsFullyNonlinearPDE (k : ℕ) (Φ : PDEJet k E ℝ → E → ℝ) : Prop :=
  ¬ IsQuasilinearPDE k Φ

/-! ### The classification inclusions -/

def IsLinearPDE (k : ℕ) (Φ : PDEJet k E ℝ → E → ℝ) : Prop :=
  ∃ (a : (j : Fin (k + 1)) → E → (PDEJetSlot (j : ℕ) E ℝ →L[ℝ] ℝ)) (f : E → ℝ),
    ∀ (ξ : PDEJet k E ℝ) (x : E), Φ ξ x = (∑ j, a j x (ξ j)) - f x

entries.body:
An expression of the form
\begin{equation}
\mathbf{F}(D^k \mathbf{u}(x), D^{k-1}\mathbf{u}(x), \ldots, D\mathbf{u}(x), \mathbf{u}(x), x) = 0 \qquad (x \in U)
\tag{2}
\end{equation}
is called a $k^{\text{th}}$-order \textit{system of partial differential equations}, where
$$\mathbf{F} : \R^{mn^k} \times \R^{mn^{k-1}} \times \cdots \times \R^{mn} \times \R^m \times U \to \R^m$$
is given and
$$\mathbf{u} : U \to \R^m, \quad \mathbf{u} = (u^1, \ldots, u^m)$$
is the unknown.

lean.code:
def IsLinearPDESystemGen (k : ℕ) (Φ : PDEJet k E V → E → W) : Prop :=
  ∃ (A : (j : Fin (k + 1)) → E → (PDEJetSlot (j : ℕ) E V →L[ℝ] W)) (f : E → W),
    ∀ (ξ : PDEJet k E V) (x : E), Φ ξ x = (∑ j, A j x (ξ j)) - f x

def IsHomogeneousLinearPDESystemGen (k : ℕ) (Φ : PDEJet k E V → E → W) : Prop :=
  ∃ A : (j : Fin (k + 1)) → E → (PDEJetSlot (j : ℕ) E V →L[ℝ] W),
    ∀ (ξ : PDEJet k E V) (x : E), Φ ξ x = ∑ j, A j x (ξ j)

def transportSymbol (n : ℕ) (b : Fin n → ℝ) :
    PDEJet 1 (SpaceTime n) ℝ → SpaceTime n → ℝ :=
  fun ξ _ => timeD1 n (ξ 1) + ∑ i : Fin n, b i * jetD1 (spaceDir n i) (ξ 1)

def liouvilleSymbol (n : ℕ) (b : Fin n → ℝ) :
    PDEJet 1 (SpaceTime n) ℝ → SpaceTime n → ℝ :=
  fun ξ _ => timeD1 n (ξ 1) - spatialFirstOrder n b (ξ 1)

def schrodingerSystemSymbol (n : ℕ) :
    PDEJet 2 (SpaceTime n) (EuclideanℝN 2) → SpaceTime n → EuclideanℝN 2 :=
  fun ξ _ => spatialLaplaceV n 2 (ξ 2) + rot2 (timeD1V n 2 (ξ 1))

def kolmogorovSymbol (n : ℕ) (a : Fin n → Fin n → ℝ) (b : Fin n → ℝ) :
    PDEJet 2 (SpaceTime n) ℝ → SpaceTime n → ℝ :=
  fun ξ _ => timeD1 n (ξ 1) - spatialSecondOrder n a (ξ 2) + spatialFirstOrder n b (ξ 1)

def fokkerPlanckSymbol (n : ℕ) (a : Fin n → Fin n → ℝ) (b : Fin n → ℝ) :
    PDEJet 2 (SpaceTime n) ℝ → SpaceTime n → ℝ :=
  fun ξ _ => timeD1 n (ξ 1) - spatialSecondOrder n a (ξ 2) - spatialFirstOrder n b (ξ 1)

def generalWaveSymbol (n : ℕ) (a : Fin n → Fin n → ℝ) (b : Fin n → ℝ) :
    PDEJet 2 (SpaceTime n) ℝ → SpaceTime n → ℝ :=
  fun ξ _ => timeD2 n (ξ 2) - spatialSecondOrder n a (ξ 2) + spatialFirstOrder n b (ξ 1)

def eikonalSymbol (E : Type*) [NormedAddCommGroup E] [NormedSpace ℝ E] :
    PDEJet 1 E ℝ → E → ℝ :=
  fun ξ _ => ‖ξ 1‖ - 1

def nonlinearPoissonSymbol (n : ℕ) (f : ℝ → ℝ) :
    PDEJet 2 (EuclideanℝN n) ℝ → EuclideanℝN n → ℝ :=
  fun ξ _ => -laplaceContraction n (ξ 2) - f (jetEval (EuclideanℝN n) (ξ 0))

def mongeAmpereSymbol (f : EuclideanℝN 2 → ℝ) :
    PDEJet 2 (EuclideanℝN 2) ℝ → EuclideanℝN 2 → ℝ :=
  fun ξ x => mongeDet (ξ 2) - f x

def hamiltonJacobiSymbol (n : ℕ) (H : (Fin n → ℝ) → SpaceTime n → ℝ) :
    PDEJet 1 (SpaceTime n) ℝ → SpaceTime n → ℝ :=
  fun ξ x => timeD1 n (ξ 1) + H (fun i => jetD1 (spaceDir n i) (ξ 1)) x

def reactionDiffusionSymbol (n : ℕ) (f : ℝ → ℝ) :
    PDEJet 2 (SpaceTime n) ℝ → SpaceTime n → ℝ :=
  fun ξ _ => timeD1 n (ξ 1) - spatialLaplace n (ξ 2) - f (jetEval (SpaceTime n) (ξ 0))

def nonlinearWaveSymbol (n : ℕ) (f : ℝ → ℝ) :
    PDEJet 2 (SpaceTime n) ℝ → SpaceTime n → ℝ :=
  fun ξ _ => timeD2 n (ξ 2) - spatialLaplace n (ξ 2) - f (jetEval (SpaceTime n) (ξ 0))

def kdvSymbol : PDEJet 3 (SpaceTime 1) ℝ → SpaceTime 1 → ℝ :=
  fun ξ _ => timeD1 1 (ξ 1) + jetEval (SpaceTime 1) (ξ 0) * jetD1 (spaceDir 1 0) (ξ 1)
    + jetD3 (spaceDir 1 0) (ξ 3)

def linearElasticityEquilibriumSymbol (n : ℕ) (μ lam : ℝ) :
    PDEJet 2 (EuclideanℝN n) (EuclideanℝN n) → EuclideanℝN n → EuclideanℝN n :=
  fun ξ _ => μ • vectorLaplace n (ξ 2) + (lam + μ) • gradDiv n (ξ 2)

def linearElasticityEvolutionSymbol (n : ℕ) (μ lam : ℝ) :
    PDEJet 2 (SpaceTime n) (EuclideanℝN n) → SpaceTime n → EuclideanℝN n :=
  fun ξ _ => timeD1V n n (ξ 1) - elasticOperatorST n μ lam (ξ 2)

def reactionDiffusionSystemSymbol (n m : ℕ) (f : EuclideanℝN m → EuclideanℝN m) :
    PDEJet 2 (SpaceTime n) (EuclideanℝN m) → SpaceTime n → EuclideanℝN m :=
  fun ξ _ => timeD1V n m (ξ 1) - spatialLaplaceV n m (ξ 2) - f (jetEvalV n m (ξ 0))

def eulerSymbol (n : ℕ) :
    PDEJet 1 (SpaceTime n) (EuclideanℝN (n + 1)) → SpaceTime n → EuclideanℝN (n + 1) :=
  fun ξ _ => eulerOp n (ξ 0) (ξ 1)

def nsSymbol (n : ℕ) :
    PDEJet 2 (SpaceTime n) (EuclideanℝN (n + 1)) → SpaceTime n → EuclideanℝN (n + 1) :=
  fun ξ _ => viscousOp n (ξ 2) + eulerOp n (ξ 0) (ξ 1)

