We say that a given problem for a partial differential equation is \textit{well-posed} if

(a) the problem in fact has a solution;

(b) this solution is unique;

and

(c) the solution depends continuously on the data given in the problem.

lean.code:
def PDEProblem.IsWellPosed {D S : Type*} [TopologicalSpace D] [TopologicalSpace S]
    (P : PDEProblem D S) : Prop :=
  ∃ Φ : D → S, Continuous Φ ∧ ∀ d, P.sol d = {Φ d}

def partialDeriv (i : Fin n) (f : EuclideanSpace ℝ (Fin n) → ℝ) :
    EuclideanSpace ℝ (Fin n) → ℝ :=
  fun x => fderiv ℝ f x (EuclideanSpace.single i 1)

def multiPartial (α : Fin n → ℕ) (f : EuclideanSpace ℝ (Fin n) → ℝ) :
    EuclideanSpace ℝ (Fin n) → ℝ :=
  (List.finRange n).foldr (fun i g => (partialDeriv i)^[α i] g) f

def transportSolutionNonhom (n : ℕ) (b : Fin n → ℝ) (g : EuclideanℝN n → ℝ)
    (f : SpaceTime n → ℝ) : SpaceTime n → ℝ :=
  fun p => g (transportProj n b p) + ∫ s in (0:ℝ)..(p 0), f (p + (s - p 0) • charDir n b)

def laplaceFund (n : ℕ) (x : EuclideanSpace ℝ (Fin n)) : ℝ :=
  if n = 2 then -(1 / (2 * π)) * Real.log ‖x‖
  else (1 / ((n : ℝ) * ((n : ℝ) - 2) * unitBallVolume n)) * ‖x‖ ^ ((2 : ℝ) - n)

