entries.body:
We say that a Lipschitz continuous function $u : \R^n \times [0,\infty) \to \R$ is a weak solution of the initial-value problem:

$$(38) \quad \begin{cases} u_t + H(Du) = 0 & \text{in } \R^n \times (0,\infty) \\ u = g & \text{on } \R^n \times \{t = 0\} \end{cases}$$

provided
\begin{enumerate}
\item[(a)] $u(x,0) = g(x)$ $(x \in \R^n)$,
\item[(b)] $u_t(x,t) + H(Du(x,t)) = 0$ \textit{for a.e.} $(x,t) \in \R^n \times (0,\infty)$,
\end{enumerate}
and
\begin{enumerate}
\item[(c)] $u(x+z,t) - 2u(x,t) + u(x-z,t) \leq C \left(1 + \frac{1}{t}\right)|z|^2$
\end{enumerate}
for some constant $C \geq 0$ and all $x, z \in \R^n, t > 0$.

If $u\in L^1(\R^n)$, we define its \textit{Fourier transform}
$$(1) \quad \hat u(y) := \frac{1}{(2\pi)^{n/2}}\int_{\R^n} e^{-ix\cdot y}u(x)\,dx \quad (y\in\R^n)$$
and its \textit{inverse Fourier transform}
$$(2) \quad \check u(y) := \frac{1}{(2\pi)^{n/2}}\int_{\R^n} e^{ix\cdot y}u(x)\,dx \quad (y\in\R^n).$$
Since $|e^{\pm ix\cdot y}|=1$ and $u\in L^1(\R^n)$, these integrals converge for each $y\in\R^n$.

Assume $u \in W^{k,p}(U)$ for some $1 \le p < \infty$, and set
$$u^\varepsilon = \eta_\varepsilon * u \text{ in } U_\varepsilon.$$
Then
\begin{enumerate}
\item[(i)] $u^\varepsilon \in C^\infty(U_\varepsilon)$ for each $\varepsilon > 0$,
\end{enumerate}
and
\begin{enumerate}
\item[(ii)] $u^\varepsilon \to u$ in $W^{k,p}_{\text{loc}}(U)$, as $\varepsilon \to 0$.
\end{enumerate}

Assume $U$ is bounded and $\partial U$ is $C^1$. Select a bounded open set $V$ such that $U \CC V$. Then there exists a bounded linear operator
$$(1) \quad E: W^{1,p}(U) \to W^{1,p}(\R^n)$$
such that for each $u \in W^{1,p}(U)$:
\begin{itemize}
\item[(i)] $Eu = u$ a.e. in $U$,
\item[(ii)] $Eu$ has support within $V$,
\end{itemize}
and
\begin{itemize}
\item[(iii)] $\|Eu\|_{W^{1,p}(\R^n)} \le C\|u\|_{W^{1,p}(U)},$
\end{itemize}
the constant $C$ depending only on $p$, $U$, and $V$.

Assume $U$ is bounded and $\partial U$ is $C^1$. Then there exists a bounded linear operator
$$T : W^{1,p}(U) \to L^p(\partial U)$$
such that
\begin{itemize}
\item[(i)] $Tu = u|_{\partial U}$ if $u \in W^{1,p}(U) \cap C(\overline{U})$
\end{itemize}
and
\begin{itemize}
\item[(ii)] $$\|Tu\|_{L^p(\partial U)} \le C\|u\|_{W^{1,p}(U)},$$
\end{itemize}
for each $u \in W^{1,p}(U)$, with the constant $C$ depending only on $p$ and $U$.

The space
$$L^p(0, T; X)$$
consists of all measurable functions $\mathbf{u} : [0, T] \to X$ with
\begin{itemize}
\item[(i)] $\|\mathbf{u}\|_{L^p(0,T;X)} := \left(\int_0^T \|\mathbf{u}(t)\|^p\,dt\right)^{1/p} < \infty$
\end{itemize}
for $1 \le p < \infty$, and
\begin{itemize}
\item[(ii)] $\|\mathbf{u}\|_{L^\infty(0,T;X)} := \text{ess sup}_{0 \le t \le T} \|\mathbf{u}(t)\| < \infty$.
\end{itemize}

We say the Lagrangian $L$ satisfies the coercivity condition (for the exponent $q$ of (3)) if
\[
\begin{cases}
\text{there exist constants } \alpha > 0, \beta \geq 0 \text{ such that} \\
L(p, z, x) \geq \alpha|p|^q - \beta \\
\text{for all } p \in \R^n, z \in \R, x \in U.
\end{cases}
\tag{4}
\]

Thus $u$ is a weak solution of the nonlinear boundary-value problem
\[
\begin{cases}
-\Delta u = \lambda g(u) & \text{in } U \\
u = 0 & \text{on } \partial U,
\end{cases}
\tag{11}
\]
where $\lambda$ is the \textit{Lagrange multiplier} corresponding to the \textit{integral constraint}
\[
J[u] = 0.
\tag{12}
\]
A problem of the form (11) for the unknowns $(u,\lambda)$, with $u \not\equiv 0$, is a \textit{nonlinear eigenvalue problem}.

We interpret (33) as saying that $\mathbf{u} = (u^1, \ldots, u^m)$ is a weak solution of the boundary-value problem
\[
\begin{cases} -\Delta \mathbf{u} = |D\mathbf{u}|^2 \mathbf{u} & \text{in } U \\ \mathbf{u} = \mathbf{g} & \text{on } \partial U. \end{cases}
\tag{34}
\]
The \textit{function} $\lambda = |D\mathbf{u}|^2$ is the Lagrange multiplier corresponding to the \textit{pointwise} constraint $|\mathbf{u}| = 1$. Note carefully that for a single, integral constant (\cref{sec:nonlinear-eigenvalue-problems}) the Lagrange multiplier is a number, but for a pointwise constraint it is a function.

We interpret (39) as saying that $(\mathbf{u}, p)$ form a weak solution of \textit{Stokes' problem}
\[
\begin{cases}
-\Delta \mathbf{u} = \mathbf{f} - Dp & \text{in } U \\
\Div \mathbf{u} = 0 & \text{in } U \\
\mathbf{u} = 0 & \text{on } \partial U.
\end{cases}
\tag{40}
\]
The function $p$ is the \textit{pressure} and arises as a Lagrange multiplier corresponding to the \textit{incompressibility condition} $\Div \mathbf{u} = 0$.

Let us investigate the solvability of the initial/boundary-value problem for the \textit{reaction-diffusion system}
\[
\begin{cases}
\mathbf{u}_t - \Delta \mathbf{u} = f(\mathbf{u}) & \text{in } U_T \\
\mathbf{u} = 0 & \text{on } \partial U \times [0,T] \\
\mathbf{u} = \mathbf{g} & \text{on } U \times \{t = 0\}.
\end{cases}
\tag{2}
\]
Here $\mathbf{u} = (u^1, \ldots, u^m)$, $\mathbf{g} = (g^1, \ldots, g^m)$, and as usual $U_T = U \times (0, T]$, where $U \subset \R^n$ is open and bounded, with smooth boundary. The time $T > 0$ is fixed. We assume that the initial function $\mathbf{g}$ belongs to $H^1_0(U; \R^m)$. Concerning the nonlinearity, let us suppose
\[
f : \R^m \to \R^m \text{ is Lipschitz continuous.}
\tag{3}
\]

Suppose $V \subset \R^n$ is open, $v \in C^2(\overline{V})$, and $c \in L^\infty(V)$. Assume
\[
\begin{cases} -\Delta v + cv \geq 0 & \text{in } V \\ v \geq 0 & \text{in } V. \end{cases}
\tag{4}
\]
Suppose also $v \not\equiv 0$.
\begin{enumerate}
\item[(i)] If $x^0 \in \partial V$, $v(x^0) = 0$, and $V$ satisfies the interior ball condition at $x^0$, then
\[
\frac{\partial v}{\partial \nu}(x^0) < 0.
\tag{5}
\]
\item[(ii)] Furthermore,
\[
v > 0 \text{ in } V.
\tag{6}
\]
\end{enumerate}
Observe that we are here making no hypothesis concerning the sign of the zeroth-order coefficient $c$.

Let $I : H \to (-\infty, +\infty]$ be convex and proper.
\begin{enumerate}
\item[(i)] For each $u \in H$, we write
\[
\partial I[u] := \{v \in H \mid I[w] \ge I[u] + (v, w-u) \text{ for all } w \in H\}.
\tag{1}
\]
The mapping $\partial I : H \to 2^H$ is the \textit{subdifferential} of $I$.
\item[(ii)] We say $u \in D(\partial I)$, the domain of $\partial I$, provided $\partial I[u] \ne \emptyset$.
\end{enumerate}

\begin{enumerate}
\item[(i)] A family $\{S(t)\}_{t \geq 0}$ of nonlinear operators mapping $H$ into $H$ is called a \textit{nonlinear semigroup} if conditions (11)--(13) are satisfied.
\item[(ii)] We say $\{S(t)\}_{t \geq 0}$ is a \textit{contraction semigroup} if in addition
\[
\|S(t)u - S(t)\hat{u}\| \leq \|u - \hat{u}\| \quad (t \geq 0, u, \hat{u} \in H).
\tag{14}
\]
\end{enumerate}

For each $u \in D(\partial I)$ there exists a unique function
\[
\mathbf{u} \in C([0, \infty); H), \text{ with } \mathbf{u}' \in L^\infty(0, \infty; H),
\tag{16}
\]
such that
\begin{enumerate}
\item[(i)] $\mathbf{u}(0) = u$,
\item[(ii)] $\mathbf{u}(t) \in D(\partial I)$ for each $t > 0$,
\end{enumerate}
and
\begin{enumerate}
\item[(iii)] $\mathbf{u}'(t) \in -\partial I[\mathbf{u}(t)]$ for a.e. $t \geq 0$.
\end{enumerate}

\begin{enumerate}
\item[(i)] $I : H \to (-\infty, +\infty]$ is convex, proper and lower semicontinuous.
\item[(ii)] $D(\partial I) = H^2(U) \cap H_0^1(U)$.
\item[(iii)] If $u \in D(\partial I)$, then $\partial I$ is single-valued and
\[
\partial I[u] = -\sum_{i=1}^n (L_{p_i}(Du))_{x_i} \quad \text{a.e.}
\]
\end{enumerate}

