\begin{cases}
|H(p,x) - H(q,x)| \leq C|p - q| \\
|H(p,x) - H(p,y)| \leq C|x - y|(1 + |p|)
\end{cases}
\tag{3}
\]
for $x, y, p, q \in \R^n$ and some constant $C \geq 0$.

The method of \textit{dynamic programming} investigates the above minimization problem by turning attention to the \textit{value function}
\[
u(x,t) := \inf_{\alpha(\cdot) \in \mathcal{A}} C_{x,t}[\alpha(\cdot)] \quad (x \in \R^n, 0 \le t \le T).
\tag{6}
\]

The value function $u$ is the unique viscosity solution of this terminal-value problem for the Hamilton-Jacobi-Bellman equation:
\[
\begin{cases}
u_t + \min_{a \in A}\{f(x,a) \cdot Du + h(x,a)\} = 0 & \text{in } \R^n \times (0,T) \\
u = g & \text{on } \R^n \times \{t = T\}.
\end{cases}
\tag{22}
\]

We have now shown that the value function $u$, defined by (6), is the unique viscosity solution of the terminal-value problem (22) for the Hamilton-Jacobi-Bellman equation. How does this PDE help us solve the problem of synthesizing an optimal control? In informal terms, the method is this. Given an initial time $0 < t \leq T$ and an initial state $x \in \R^n$, we consider the optimal ODE
\[
\begin{cases} \dot{x}^*(s) = f(x^*(s), \alpha^*(s)) & (t < s < T) \\ x^*(t) = x, \end{cases}
\tag{41}
\]
where at each time $s$, $\alpha^*(s) \in A$ is selected so that
\[
\begin{aligned}
f(x^*(s), \alpha^*(s)) \cdot Du(x^*(s), s) + h(x^*(s), \alpha^*(s)) \\
= H(Du(x^*(s), s), x^*(s)).
\end{aligned}
\tag{42}
\]
In other words, given the system is at the point $x^*(s)$ at time $s$, we adjust the optimal control value $\alpha^*(s)$ so as to attain the minimum in the definition (23) of the Hamiltonian $H$. We call $\alpha^*(\cdot)$ so defined a \textit{feedback control}.

It is easy to check that this prescription does in fact generate a minimum cost trajectory, at least in regions where $u$ and $\alpha^*(\cdot)$ are smooth (so that (42) makes sense). There are however problems in interpreting (42) at points where the gradient $Du$ does not exist. $\square$

Given a fixed state $z_0\in\mathbb{R}^m$, we define the $k^{\text{th}}$-\textit{rarefaction curve}
$$R_k(z_0)$$
to be the path in $\mathbb{R}^m$ of the solution of the ODE (6) which passes through $z_0$.

(i) (Big-oh notation.) \textit{We write}
$$f = O(g) \quad \text{as } x \to x_0,$$
\textit{provided there exists a constant } $C$ \textit{ such that}
$$|f(x)| \leq C|g(x)|$$
\textit{for all } $x$ \textit{ sufficiently close to } $x_0$.

(ii) (Little-oh notation.) \textit{We write}
$$f = o(g) \quad \text{as } x \to x_0,$$
\textit{provided}
$$\lim_{x \to x_0} \frac{|f(x)|}{|g(x)|} = 0.$$

\textit{We say a sequence} $\{u_k\}_{k=1}^{\infty} \subset X$ \textit{converges to} $u \in X$, \textit{written}
$$u_k \to u,$$
\textit{if}
$$\lim_{k \to \infty} \|u_k - u\| = 0.$$

$H^*$ \textit{can be canonically identified with} $H$; \textit{more precisely, for each} $u^* \in H^*$ \textit{there exists a unique element} $u \in H$ \textit{such that}
$$(u^*, v) = (u, v) \quad \text{for all } v \in H.$$
\textit{The mapping} $u^* \mapsto u$ \textit{is a linear isomorphism of} $H^*$ \textit{onto} $H$.

\textit{A bounded linear operator}
$$K : X \to Y$$
\textit{is called compact provided for each bounded sequence $\{u_k\}_{k=1}^\infty \subset X$, the sequence $\{Ku_k\}_{k=1}^\infty$ is precompact in $Y$; that is, there exists a subsequence $\{u_{k_j}\}_{j=1}^\infty$ such that $\{Ku_{k_j}\}_{j=1}^\infty$ converges in $Y$.}

Let $K : H \to H$ be a compact linear operator. Then
\begin{itemize}
\item[(i)] $N(I - K)$ is finite dimensional,
\item[(ii)] $R(I - K)$ is closed,
\item[(iii)] $R(I - K) = N(I - K^*)^\perp$,
\item[(iv)] $N(I - K) = \{0\}$ if and only if $R(I - K) = H$,
\end{itemize}
\textit{and}
\begin{itemize}
\item[(v)] $\dim N(I - K) = \dim N(I - K^*)$.
\end{itemize}

\textit{Assume} $\dim H = \infty$ \textit{and} $K : H \to H$ \textit{is compact. Then}
\begin{itemize}
\item[(i)] $0 \in \sigma(K)$,
\item[(ii)] $\sigma(K) - \{0\} = \sigma_p(K) - \{0\}$,
\end{itemize}
\textit{and}
\begin{itemize}
\item[(iii)] $\left\{ \begin{array}{l} \sigma(K) - \{0\} \text{ is finite, or else} \\ \sigma(K) - \{0\} \text{ is a sequence tending to } 0. \end{array} \right.$
\end{itemize}

\textit{There exist a $\sigma$-algebra $\mathcal{M}$ of subsets of $\mathbb{R}^n$ and a mapping}
$$| \cdot | : \mathcal{M} \to [0, +\infty]$$
\textit{with the following properties:}

\begin{enumerate}
\item[(i)] \textit{Every open subset of $\mathbb{R}^n$, and thus every closed subset of $\mathbb{R}^n$, belong to $\mathcal{M}$.}
\item[(ii)] \textit{If $B$ is any ball in $\mathbb{R}^n$, then $|B|$ equals the $n$-dimensional volume of $B$.}
\item[(iii)] \textit{If $\{A_k\}_{k=1}^{\infty} \subset \mathcal{M}$ and the sets $\{A_k\}_{k=1}^{\infty}$ are pairwise disjoint, then}
$$(1) \quad \left| \bigcup_{k=1}^{\infty} A_k \right| = \sum_{k=1}^{\infty} |A_k| \quad \text{(``countable additivity")}.$$
\item[(iv)] \textit{If $A \subseteq B$, where $B \in \mathcal{M}$ and $|B| = 0$, then $A \in \mathcal{M}$ and $|A| = 0$.}
\end{enumerate}

\textbf{Notation.} The sets in $\mathcal{M}$ are called \textit{Lebesgue measurable sets} and $| \cdot |$ is $n$-dimensional \textit{Lebesgue measure}. $\square$
